<script>
// ═══════════════════════════════════════════════════════════════════════════
// PER-PHASE ADDITION (not template-owned): segmentation has no decisive ratio
// and no landmarks, so the template's evidence banner / Values tab render
// only a neutral "no measurement yet" note. The structural verification that
// DOES exist for this phase (bicondylar-discriminator identity check,
// connected-component counts, per-structure role/confidence, escalated
// structures) lives in REVIEW_EVIDENCE.structural — this block surfaces it as
// plain text in #structure-notes so the reviewer isn't left with only "trust
// the mesh colors". Read-only: textContent only, no innerHTML, no eval, no
// network, no export/navigation — same trust boundary as the core script.
(function () {
  "use strict";
  var EV = window.REVIEW_EVIDENCE || {};
  var st = EV.structural;
  var el = document.getElementById("structure-notes");
  if (!el || !st) return;

  function humanize(id) {
    return String(id).replace(/_/g, " ").replace(/\b\w/g, function (c) { return c.toUpperCase(); });
  }

